function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
        rangeMin = clamp(lo, min, max);
        rangeMax = clamp(hi, min, max);
        if (rangeMin > rangeMax) throw new RangeError(`Invalid range: ${rangePart}`);
      } else {
        rangeMin = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) result.push(v);
    return result;
  }

  // Range: a-b
  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map((n) => parseInt(n, 10));
    const start = clamp(lo, min, max);
    const end = clamp(hi, min, max);
    if (start > end) throw new RangeError(`Invalid range: ${field}`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) throw new SyntaxError(`Invalid cron field value: "${field}"`);
  return [clamp(num, min, max)];
}

