  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function validateValue(value: number, spec: FieldSpec, field: string): void {
  if (value < spec.min || value > spec.max) {
    throw new RangeError(
      `Value ${value} is out of range [${spec.min}-${spec.max}] for field "${field}"`
    );
  }
}

function parseToken(token: string, spec: FieldSpec, field: string): number[] {
  // Wildcard
  if (token === "*") {
    return rangeArray(spec.min, spec.max);
  }

  // Step: */n or start/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${token}" for field "${field}"`);
    }
    if (rangePart === "*") {
      return rangeArray(spec.min, spec.max, step);
    }
    const start = parseInt(rangePart, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid step expression "${token}" for field "${field}"`);
    }
    validateValue(start, spec, field);
    return rangeArray(start, spec.max, step);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [fromStr, toStr] = token.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to)) {
      throw new SyntaxError(`Invalid range "${token}" for field "${field}"`);
    }
    if (from > to) {
      throw new RangeError(`Range start ${from} exceeds end ${to} in field "${field}"`);
    }
    validateValue(from, spec, field);
    validateValue(to, spec, field);
    return rangeArray(from, to);
  }

  // Single number
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${token}" for field "${field}"`);
  }
  validateValue(value, spec, field);
  return [value];
}

function parseField(expression: string, spec: FieldSpec, field: string): number[] {
  const values = expression
    .split(",")
    .flatMap((token) => parseToken(token.trim(), spec, field));

  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
}

