function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: "${stepStr}"`);

    let start = min;
    let end = max;

    if (left !== "*") {
      if (left.includes("-")) {
        const [a, b] = left.split("-").map(Number);
        start = a;
        end = b;
      } else {
        start = parseInt(left, 10);
      }
    }

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid step expression: "${segment}"`);
    return range(start, end, step);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const [a, b] = segment.split("-").map(Number);
    if (isNaN(a) || isNaN(b)) throw new Error(`Invalid range: "${segment}"`);
    if (a < min || b > max || a > b) {
      throw new Error(`Range "${segment}" out of bounds [${min}-${max}]`);
    }
    return range(a, b);
  }

  // Single value
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: "${segment}"`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min}-${max}]`);
  return [n];
}

