      end = max;
    } else if (rangePart.includes("-")) {
      const [rangeStart, rangeEnd] = rangePart.split("-").map(Number);
      if (isNaN(rangeStart) || isNaN(rangeEnd)) {
        throw new Error(`Invalid range in step expression "${field}" for ${fieldName}`);
      }
      start = rangeStart;
      end = rangeEnd;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new Error(`Invalid start value in step expression "${field}" for ${fieldName}`);
      }
      end = max;
    }

    if (start < min || end > max) {
      throw new Error(
        `Step range ${start}-${end} out of bounds [${min}-${max}] for ${fieldName}`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Handle range (e.g., "1-5")
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${field}" for ${fieldName}`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} for ${fieldName}`);
    }
    if (start < min || end > max) {
      throw new Error(
        `Range ${start}-${end} out of bounds [${min}-${max}] for ${fieldName}`
      );
    }

    return generateRange(start, end);
  }

  // Handle single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${field}" for ${fieldName}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}] for ${fieldName}`);
  }

  return [value];
}

