}

function unique(arr: number[]): number[] {
  return [...new Set(arr)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range: ${rangePart}`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: ${rangePart}`);
      end = max;
    }

    validateRange(start, min, max);
    validateRange(end, min, max);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").flatMap((part) => parseSegment(part.trim(), min, max));
    return unique(values);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    validateRange(start, min, max);
    validateRange(end, min, max);
    if (start > end) throw new Error(`Range start ${start} is greater than end ${end}`);
    return range(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new Error(`Invalid value: ${segment}`);
  validateRange(num, min, max);
  return [num];
}

function validateRange(value: number, min: number, max: number): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }
}

function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const segments = [minutePart, hourPart, domPart, monthPart, dowPart];

  const result = {} as CronResult;

  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    let values = parseSegment(segments[i], min, max);

    // Normalize dayOfWeek: treat 7 as 0 (Sunday)
    if (field === "dayOfWeek") {
      values = unique(values.map((v) => (v === 7 ? 0 : v)));
    }

    result[field] = values;
  }

  return result;
}

