export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — split and recurse
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start/n
  if (expr.includes("/")) {
    const [left, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expr}"`);
    }
    let start = min;
    let end = max;
    if (left !== "*") {
      if (left.includes("-")) {
        const [lo, hi] = left.split("-").map(Number);
        start = clamp(lo, min, max);
        end = clamp(hi, min, max);
        if (start > end) throw new Error(`Invalid range "${left}"`);
      } else {
        start = clamp(parseInt(left, 10), min, max);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [loStr, hiStr] = expr.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max);
    const hi = clamp(parseInt(hiStr, 10), min, max);
    if (lo > hi) throw new Error(`Invalid range "${expr}": start > end`);
    return range(lo, hi);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value "${expr}"`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}
